  vec3 col = base + (g - 0.5) * 0.12;
  gl_FragColor = vec4(col, 1.0);
}

void main(){
  vec2 uv = gl_FragCoord.xy / u_resolution.xy;
  float t = u_time * 0.3;
  float a = sin(uv.x * 3.0 + t) + cos(uv.y * 3.0 - t);
  vec3 c1 = vec3(0.36, 0.40, 0.95);
  vec3 c2 = vec3(0.95, 0.45, 0.72);
  vec3 c3 = vec3(0.20, 0.85, 0.80);
  vec3 col = mix(mix(c1, c2, uv.x), c3, 0.5 + 0.5 * sin(a));
  gl_FragColor = vec4(col, 1.0);
}

void main(){
  vec2 uv = gl_FragCoord.xy / u_resolution.xy;
  float t = u_time * 0.6;
  float v = sin(uv.x * 8.0 + t) + sin(uv.y * 8.0 - t) + sin((uv.x + uv.y) * 8.0 + t);
  v *= 0.33;
  vec3 col = 0.5 + 0.5 * cos(6.2831 * (v + vec3(0.0, 0.33, 0.67)));
  col = mix(vec3(0.05, 0.06, 0.12), col, 0.85);
  gl_FragColor = vec4(col, 1.0);
}

float hash(vec2 p){ return fract(sin(dot(p, vec2(127.1, 311.7))) * 43758.5453); }
float noise(vec2 p){
  vec2 i = floor(p), f = fract(p);
  float a = hash(i), b = hash(i + vec2(1.0, 0.0));
  float c = hash(i + vec2(0.0, 1.0)), d = hash(i + vec2(1.0, 1.0));
  vec2 u = f * f * (3.0 - 2.0 * f);
  return mix(a, b, u.x) + (c - a) * u.y * (1.0 - u.x) + (d - b) * u.x * u.y;
}
void main(){
  vec2 uv = gl_FragCoord.xy / u_resolution.xy;
  float n = 0.5 * noise(uv * 6.0 + u_time * 0.4) + 0.5 * noise(uv * 12.0 - u_time * 0.25);
  vec3 col = mix(vec3(0.05, 0.07, 0.12), vec3(0.42, 0.55, 0.95), n);
  gl_FragColor = vec4(col, 1.0);
}

