  float s = 0.5 + 0.5 * sin(y * 20.0);
  vec3 col = mix(vec3(0.06, 0.09, 0.18), vec3(0.30, 0.55, 0.95), s);
  gl_FragColor = vec4(col, 1.0);
}

void main(){
  vec2 uv = gl_FragCoord.xy / u_resolution.xy;
  vec2 g = fract(uv * 24.0) - 0.5;
  float t = u_time * 0.8;
  float r = 0.30 + 0.18 * sin(uv.x * 6.0 + uv.y * 6.0 + t);
  float d = smoothstep(r, r - 0.08, length(g));
  vec3 bg = mix(vec3(0.06, 0.07, 0.11), vec3(0.10, 0.12, 0.20), uv.y);
  vec3 col = mix(bg, vec3(0.55, 0.60, 0.95), d);
  gl_FragColor = vec4(col, 1.0);
